+        // Release
+        assert!(table.release(page, txn_a));
+        let ctx_released = DiagContext::new(BEAD_ID)
+            .case("lock_released")
+            .invariant("Released lock has no holder");
+        diag_assert_eq!(ctx_released, table.holder(page), None);
+    }
